3	// ── Thumbnail ───────────────────────────────────────────────────────────────
4	// Priority: explicit thumbnail image > live iframe of the URL > typographic placeholder.
5	function Thumb({ url, model, harness, thumbnail }) {
6	  const wrapRef = useRef(null);
7	  const frameRef = useRef(null);
8	  const [imgFailed, setImgFailed] = useState(false);
9	  const [iframeLoaded, setIframeLoaded] = useState(false);
10	  const [iframeFailed, setIframeFailed] = useState(false);
11	
12	  const useImage = thumbnail && !imgFailed;
13	  const useIframe = !useImage && !iframeFailed;
14	
15	  // Scale 1440x900 iframe to fit the card thumb
16	  useEffect(() => {
17	    if (!useIframe) return;
18	    const wrap = wrapRef.current;
19	    const frame = frameRef.current;
20	    if (!wrap || !frame) return;
21	    const apply = () => {
22	      const w = wrap.clientWidth;
23	      const h = wrap.clientHeight;
24	      const s = Math.max(w / 1440, h / 900);
25	      frame.style.transform = `scale(${s})`;
26	    };
27	    apply();
28	    const ro = new ResizeObserver(apply);
29	    ro.observe(wrap);
30	    return () => ro.disconnect();
31	  }, [useIframe]);
32	
33	  useEffect(() => {
34	    if (!useIframe) return;
35	    const t = setTimeout(() => { if (!iframeLoaded) setIframeFailed(true); }, 4500);
36	    return () => clearTimeout(t);
37	  }, [useIframe, iframeLoaded]);
38	
39	  return (
40	    <div className="card__thumb">
41	      <div className="thumb__frame-wrap" ref={wrapRef}>
42	        {useImage && (
43	          <img
44	            className="thumb__image"
45	            src={thumbnail}
46	            alt={`${model} · ${harness}`}
47	            loading="lazy"
48	            onError={() => setImgFailed(true)}
49	          />
50	        )}
51	        {useIframe && (
52	          <iframe
53	            ref={frameRef}
54	            className="thumb__frame"
55	            src={url}
56	            loading="lazy"
57	            sandbox="allow-same-origin"
58	            onLoad={() => setIframeLoaded(true)}
59	            onError={() => setIframeFailed(true)}
60	            title={`${model} · ${harness}`}
61	          />
62	        )}
63	        {!useImage && (iframeFailed || !iframeLoaded) && (
64	          <div className="thumb__placeholder">
65	            <div className="mono">{harness}</div>
66	            <div className="thumb__placeholder-title">{model}</div>
67	            <div className="mono" style={{ opacity: 0.6 }}>
68	              {(() => { try { return new URL(url).host; } catch { return url; } })()}
69	            </div>
70	          </div>
71	        )}
72	      </div>
73	      <div className="card__thumb-overlay">
74	        Open
75	        <svg viewBox="0 0 12 12" fill="none" stroke="currentColor" strokeWidth="1.5">
76	          <path d="M3 9L9 3M9 3H4M9 3V8" strokeLinecap="round" strokeLinejoin="round"/>
77	        </svg>
78	      </div>
79	    </div>
80	  );
81	}
