83	// ── Card ────────────────────────────────────────────────────────────────────
84	function Card({ run, idx }) {
85	  return (
86	    <a className="card" href={run.url} target="_blank" rel="noopener noreferrer">
87	      <Thumb url={run.url} model={run.model} harness={run.harness} thumbnail={run.thumbnail} />
88	      <div className="card__body">
89	        <div className="card__meta-row">
90	          <span className="card__model">{run.model}</span>
91	          <span className="card__harness">{run.harness}</span>
92	        </div>
93	        <h3 className="card__title">{run.title}</h3>
94	        <p className="card__notes">{run.notes}</p>
95	        <div className="card__footer">
96	          <span className="card__index">Run · {String(idx + 1).padStart(3, "0")}</span>
97	          <span className="card__visit">
98	            Visit
99	            <svg viewBox="0 0 12 12" fill="none" stroke="currentColor" strokeWidth="1.5">
100	              <path d="M2 6h8M7 3l3 3-3 3" strokeLinecap="round" strokeLinejoin="round"/>
101	            </svg>
102	          </span>
103	        </div>
104	      </div>
105	    </a>
106	  );
107	}
108	
109	function Chip({ active, onClick, label, count }) {
110	  return (
111	    <button className="chip" data-active={active} onClick={onClick}>
112	      {label}
113	      <span className="chip__count">{count}</span>
114	    </button>
115	  );
116	}
117	
118	// ── Prompt view ─────────────────────────────────────────────────────────────
119	function PromptView({ prompt, runCount }) {
120	  const [copied, setCopied] = useState(false);
121	  const copy = async () => {
122	    try {
123	      await navigator.clipboard.writeText(prompt.body);
124	      setCopied(true);
125	      setTimeout(() => setCopied(false), 1500);
126	    } catch {
127	      // Fallback
128	      const ta = document.createElement("textarea");
129	      ta.value = prompt.body;
130	      document.body.appendChild(ta);
131	      ta.select();
132	      try { document.execCommand("copy"); setCopied(true); setTimeout(() => setCopied(false), 1500); } catch {}
133	      ta.remove();
134	    }
135	  };
136	  const wordCount = prompt.body.trim().split(/\s+/).length;
137	  const charCount = prompt.body.length;
138	
139	  return (
140	    <section className="prompt-view">
141	      <div className="prompt-view__head">
142	        <div>
143	          <div className="prompt-view__eyebrow">The shared prompt</div>
144	          <h2 className="prompt-view__title">
145	            <em>{prompt.title}</em>
146	          </h2>
147	          <p className="prompt-view__summary">{prompt.summary}</p>
148	        </div>
149	        <div className="prompt-view__meta">
150	          <span><strong>{prompt.version}</strong></span>
151	          <span>Updated {prompt.updated}</span>
152	          <span>{wordCount} words · {charCount} chars</span>
153	        </div>
154	      </div>
155	
156	      <div className="prompt-card">
157	        <div className="prompt-card__bar">
158	          <div className="prompt-card__bar-left">
159	            <span className="prompt-card__dot" />
160	            <span>prompt.md</span>
161	          </div>
162	          <button className="prompt-card__copy" data-copied={copied} onClick={copy}>
163	            {copied ? (
164	              <>
165	                <svg viewBox="0 0 12 12" fill="none" stroke="currentColor" strokeWidth="1.6">
166	                  <path d="M2.5 6.5L5 9L9.5 3.5" strokeLinecap="round" strokeLinejoin="round"/>
167	                </svg>
168	                Copied
169	              </>
170	            ) : (
171	              <>
172	                <svg viewBox="0 0 12 12" fill="none" stroke="currentColor" strokeWidth="1.4">
173	                  <rect x="3" y="3" width="6.5" height="6.5" rx="1"/>
174	                  <path d="M2 8V2h6" strokeLinecap="round"/>
175	                </svg>
176	                Copy
177	              </>
178	            )}
179	          </button>
180	        </div>
181	        <pre className="prompt-card__body">{prompt.body}</pre>
182	      </div>
183	
184	      <div className="prompt-footnote">
185	        This prompt was used verbatim across all {runCount} runs in the gallery.
186	      </div>
187	    </section>
188	  );
189	}
190	
191	// ── Tweaks defaults ─────────────────────────────────────────────────────────
192	const TWEAK_DEFAULTS = /*EDITMODE-BEGIN*/{
193	  "density": "default",
194	  "sort": "default"
195	}/*EDITMODE-END*/;
196	
