254	            <span><strong>{models.length}</strong> models</span>
255	            <span><strong>{harnesses.length}</strong> harnesses</span>
256	            <span>Updated · {today}</span>
257	          </div>
258	        </div>
259	      </header>
260	
261	      <nav className="tabs" data-screen-label="Tabs">
262	        <button className="tab" data-active={tab === "runs"} onClick={() => goTab("runs")}>
263	          Runs
264	          <span className="tab__badge">{runs.length}</span>
265	        </button>
266	        <button className="tab" data-active={tab === "prompt"} onClick={() => goTab("prompt")}>
267	          Prompt
268	          <span className="tab__badge">{prompt.version || "v0"}</span>
269	        </button>
270	      </nav>
271	
272	      {tab === "runs" && (
273	        <>
274	          <section className="hero" data-screen-label="Intro">
275	            <div>
276	              <div className="hero__eyebrow">A working archive — {prompt.version || "v0.1"}</div>
