103	    background:rgba(255,255,255,.9);box-shadow:0 1px 2px rgba(0,0,0,.12);
104	    transition:left .15s cubic-bezier(.3,.7,.4,1),width .15s}
105	  .twk-seg.dragging .twk-seg-thumb{transition:none}
106	  .twk-seg button{appearance:none;position:relative;z-index:1;flex:1;border:0;
107	    background:transparent;color:inherit;font:inherit;font-weight:500;min-height:22px;
108	    border-radius:6px;cursor:default;padding:4px 6px;line-height:1.2;
109	    overflow-wrap:anywhere}
110	
111	  .twk-toggle{position:relative;width:32px;height:18px;border:0;border-radius:999px;
112	    background:rgba(0,0,0,.15);transition:background .15s;cursor:default;padding:0}
113	  .twk-toggle[data-on="1"]{background:#34c759}
114	  .twk-toggle i{position:absolute;top:2px;left:2px;width:14px;height:14px;border-radius:50%;
115	    background:#fff;box-shadow:0 1px 2px rgba(0,0,0,.25);transition:transform .15s}
116	  .twk-toggle[data-on="1"] i{transform:translateX(14px)}
117	
118	  .twk-num{display:flex;align-items:center;box-sizing:border-box;min-width:0;height:26px;padding:0 0 0 8px;
119	    border:.5px solid rgba(0,0,0,.1);border-radius:7px;background:rgba(255,255,255,.6)}
120	  .twk-num-lbl{font-weight:500;color:rgba(41,38,27,.6);cursor:ew-resize;
121	    user-select:none;padding-right:8px}
122	  .twk-num input{flex:1;min-width:0;height:100%;border:0;background:transparent;
123	    font:inherit;font-variant-numeric:tabular-nums;text-align:right;padding:0 8px 0 0;
124	    outline:none;color:inherit;-moz-appearance:textfield}
125	  .twk-num input::-webkit-inner-spin-button,.twk-num input::-webkit-outer-spin-button{
126	    -webkit-appearance:none;margin:0}
127	  .twk-num-unit{padding-right:8px;color:rgba(41,38,27,.45)}
128	
129	  .twk-btn{appearance:none;height:26px;padding:0 12px;border:0;border-radius:7px;
130	    background:rgba(0,0,0,.78);color:#fff;font:inherit;font-weight:500;cursor:default}
131	  .twk-btn:hover{background:rgba(0,0,0,.88)}
132	  .twk-btn.secondary{background:rgba(0,0,0,.06);color:inherit}
133	  .twk-btn.secondary:hover{background:rgba(0,0,0,.1)}
134	
135	  .twk-swatch{appearance:none;-webkit-appearance:none;width:56px;height:22px;
136	    border:.5px solid rgba(0,0,0,.1);border-radius:6px;padding:0;cursor:default;
137	    background:transparent;flex-shrink:0}
138	  .twk-swatch::-webkit-color-swatch-wrapper{padding:0}
139	  .twk-swatch::-webkit-color-swatch{border:0;border-radius:5.5px}
140	  .twk-swatch::-moz-color-swatch{border:0;border-radius:5.5px}
141	
142	  .twk-chips{display:flex;gap:6px}
143	  .twk-chip{position:relative;appearance:none;flex:1;min-width:0;height:46px;
144	    padding:0;border:0;border-radius:6px;overflow:hidden;cursor:default;
145	    box-shadow:0 0 0 .5px rgba(0,0,0,.12),0 1px 2px rgba(0,0,0,.06);
146	    transition:transform .12s cubic-bezier(.3,.7,.4,1),box-shadow .12s}
147	  .twk-chip:hover{transform:translateY(-1px);
148	    box-shadow:0 0 0 .5px rgba(0,0,0,.18),0 4px 10px rgba(0,0,0,.12)}
149	  .twk-chip[data-on="1"]{box-shadow:0 0 0 1.5px rgba(0,0,0,.85),
150	    0 2px 6px rgba(0,0,0,.15)}
151	  .twk-chip>span{position:absolute;top:0;bottom:0;right:0;width:34%;
152	    display:flex;flex-direction:column;box-shadow:-1px 0 0 rgba(0,0,0,.1)}
153	  .twk-chip>span>i{flex:1;box-shadow:0 -1px 0 rgba(0,0,0,.1)}
154	  .twk-chip>span>i:first-child{box-shadow:none}
155	  .twk-chip svg{position:absolute;top:6px;left:6px;width:13px;height:13px;
156	    filter:drop-shadow(0 1px 1px rgba(0,0,0,.3))}
157	`;
158	
159	// ── useTweaks ───────────────────────────────────────────────────────────────
160	// Single source of truth for tweak values. setTweak persists via the host
161	// (__edit_mode_set_keys → host rewrites the EDITMODE block on disk).
162	function useTweaks(defaults) {
163	  const [values, setValues] = React.useState(defaults);
164	  // Accepts either setTweak('key', value) or setTweak({ key: value, ... }) so a
165	  // useState-style call doesn't write a "[object Object]" key into the persisted
166	  // JSON block.
167	  const setTweak = React.useCallback((keyOrEdits, val) => {
168	    const edits = typeof keyOrEdits === 'object' && keyOrEdits !== null
169	      ? keyOrEdits : { [keyOrEdits]: val };
170	    setValues((prev) => ({ ...prev, ...edits }));
171	    window.parent.postMessage({ type: '__edit_mode_set_keys', edits }, '*');
172	    // Same-window signal so in-page listeners (deck-stage rail thumbnails)
173	    // can react — the parent message only reaches the host, not peers.
174	    window.dispatchEvent(new CustomEvent('tweakchange', { detail: edits }));
175	  }, []);
176	  return [values, setTweak];
177	}
178	
179	// ── TweaksPanel ─────────────────────────────────────────────────────────────
180	// Floating shell. Registers the protocol listener BEFORE announcing
181	// availability — if the announce ran first, the host's activate could land
182	// before our handler exists and the toolbar toggle would silently no-op.
183	// The close button posts __edit_mode_dismissed so the host's toolbar toggle
184	// flips off in lockstep; the host echoes __deactivate_edit_mode back which
185	// is what actually hides the panel.
186	function TweaksPanel({ title = 'Tweaks', noDeckControls = false, children }) {
187	  const [open, setOpen] = React.useState(false);
188	  const dragRef = React.useRef(null);
189	  // Auto-inject a rail toggle when a <deck-stage> is on the page. The
190	  // toggle drives the deck's per-viewer _railVisible via window message;
191	  // state is mirrored from the same localStorage key the deck reads so
192	  // the control reflects reality across reloads. The mechanism is the
193	  // message — authors who want custom placement can post it directly
194	  // and pass noDeckControls to suppress this one.
195	  const hasDeckStage = React.useMemo(
196	    () => typeof document !== 'undefined' && !!document.querySelector('deck-stage'),
197	    [],
198	  );
199	  // deck-stage enables its rail in connectedCallback, but this panel can
200	  // mount before that element has upgraded. The initial read catches the
201	  // common case; the listener covers mounting first. (Older deck-stage.js
202	  // copies still wait for the host's __omelette_rail_enabled postMessage —
203	  // same listener handles those.)
204	  const [railEnabled, setRailEnabled] = React.useState(
205	    () => hasDeckStage && !!document.querySelector('deck-stage')?._railEnabled,
206	  );
207	  React.useEffect(() => {
208	    if (!hasDeckStage || railEnabled) return undefined;
209	    const onMsg = (e) => {
210	      if (e.data && e.data.type === '__omelette_rail_enabled') setRailEnabled(true);
211	    };
212	    window.addEventListener('message', onMsg);
213	    return () => window.removeEventListener('message', onMsg);
214	  }, [hasDeckStage, railEnabled]);
215	  const [railVisible, setRailVisible] = React.useState(() => {
216	    try { return localStorage.getItem('deck-stage.railVisible') !== '0'; } catch (e) { return true; }
217	  });
218	  const toggleRail = (on) => {
219	    setRailVisible(on);
220	    window.postMessage({ type: '__deck_rail_visible', on }, '*');
221	  };
222	  const offsetRef = React.useRef({ x: 16, y: 16 });
223	  const PAD = 16;
224	
225	  const clampToViewport = React.useCallback(() => {
226	    const panel = dragRef.current;
227	    if (!panel) return;
228	    const w = panel.offsetWidth, h = panel.offsetHeight;
229	    const maxRight = Math.max(PAD, window.innerWidth - w - PAD);
230	    const maxBottom = Math.max(PAD, window.innerHeight - h - PAD);
231	    offsetRef.current = {
232	      x: Math.min(maxRight, Math.max(PAD, offsetRef.current.x)),
233	      y: Math.min(maxBottom, Math.max(PAD, offsetRef.current.y)),
234	    };
235	    panel.style.right = offsetRef.current.x + 'px';
236	    panel.style.bottom = offsetRef.current.y + 'px';
237	  }, []);
238	
239	  React.useEffect(() => {
240	    if (!open) return;
241	    clampToViewport();
242	    if (typeof ResizeObserver === 'undefined') {
243	      window.addEventListener('resize', clampToViewport);
244	      return () => window.removeEventListener('resize', clampToViewport);
245	    }
246	    const ro = new ResizeObserver(clampToViewport);
247	    ro.observe(document.documentElement);
248	    return () => ro.disconnect();
249	  }, [open, clampToViewport]);
250	
251	  React.useEffect(() => {
252	    const onMsg = (e) => {
253	      const t = e?.data?.type;
254	      if (t === '__activate_edit_mode') setOpen(true);
255	      else if (t === '__deactivate_edit_mode') setOpen(false);
256	    };
257	    window.addEventListener('message', onMsg);
258	    window.parent.postMessage({ type: '__edit_mode_available' }, '*');
259	    return () => window.removeEventListener('message', onMsg);
260	  }, []);
261	
262	  const dismiss = () => {
263	    setOpen(false);
264	    window.parent.postMessage({ type: '__edit_mode_dismissed' }, '*');
265	  };
266	
267	  const onDragStart = (e) => {
268	    const panel = dragRef.current;
269	    if (!panel) return;
270	    const r = panel.getBoundingClientRect();
271	    const sx = e.clientX, sy = e.clientY;
272	    const startRight = window.innerWidth - r.right;
273	    const startBottom = window.innerHeight - r.bottom;
274	    const move = (ev) => {
275	      offsetRef.current = {
276	        x: startRight - (ev.clientX - sx),
277	        y: startBottom - (ev.clientY - sy),
278	      };
279	      clampToViewport();
280	    };
281	    const up = () => {
282	      window.removeEventListener('mousemove', move);
283	      window.removeEventListener('mouseup', up);
284	    };
285	    window.addEventListener('mousemove', move);
286	    window.addEventListener('mouseup', up);
287	  };
288	
289	  if (!open) return null;
290	  return (
291	    <>
292	      <style>{__TWEAKS_STYLE}</style>
293	      <div ref={dragRef} className="twk-panel" data-noncommentable=""
294	           style={{ right: offsetRef.current.x, bottom: offsetRef.current.y }}>
295	        <div className="twk-hd" onMouseDown={onDragStart}>
296	          <b>{title}</b>
297	          <button className="twk-x" aria-label="Close tweaks"
298	                  onMouseDown={(e) => e.stopPropagation()}
299	                  onClick={dismiss}>✕</button>
300	        </div>
301	        <div className="twk-body">
302	          {children}
303	          {hasDeckStage && railEnabled && !noDeckControls && (
304	            <TweakSection label="Deck">
305	              <TweakToggle label="Thumbnail rail" value={railVisible} onChange={toggleRail} />
306	            </TweakSection>
307	          )}
308	        </div>
309	      </div>
310	    </>
311	  );
312	}
313	
314	// ── Layout helpers ──────────────────────────────────────────────────────────
315	
316	function TweakSection({ label, children }) {
317	  return (
318	    <>
319	      <div className="twk-sect">{label}</div>
320	      {children}
321	    </>
322	  );
323	}
324	
325	function TweakRow({ label, value, children, inline = false }) {
326	  return (
327	    <div className={inline ? 'twk-row twk-row-h' : 'twk-row'}>
328	      <div className="twk-lbl">
329	        <span>{label}</span>
330	        {value != null && <span className="twk-val">{value}</span>}
331	      </div>
332	      {children}
333	    </div>
334	  );
335	}
336	
337	// ── Controls ────────────────────────────────────────────────────────────────
338	
339	function TweakSlider({ label, value, min = 0, max = 100, step = 1, unit = '', onChange }) {
340	  return (
341	    <TweakRow label={label} value={`${value}${unit}`}>
342	      <input type="range" className="twk-slider" min={min} max={max} step={step}
343	             value={value} onChange={(e) => onChange(Number(e.target.value))} />
344	    </TweakRow>
345	  );
346	}
347	
348	function TweakToggle({ label, value, onChange }) {
349	  return (
350	    <div className="twk-row twk-row-h">
351	      <div className="twk-lbl"><span>{label}</span></div>
352	      <button type="button" className="twk-toggle" data-on={value ? '1' : '0'}
353	              role="switch" aria-checked={!!value}
354	              onClick={() => onChange(!value)}><i /></button>
355	    </div>
356	  );
357	}
358	
359	function TweakRadio({ label, value, options, onChange }) {
360	  const trackRef = React.useRef(null);
361	  const [dragging, setDragging] = React.useState(false);
362	  // The active value is read by pointer-move handlers attached for the lifetime
363	  // of a drag — ref it so a stale closure doesn't fire onChange for every move.
364	  const valueRef = React.useRef(value);
365	  valueRef.current = value;
366	
367	  // Segments wrap mid-word once per-segment width runs out. The track is
368	  // ~248px (280 panel − 28 body pad − 4 seg pad), each button loses 12px
369	  // to its own padding, and 11.5px system-ui averages ~6.3px/char — so 2
370	  // options fit ~16 chars each, 3 fit ~10. Past that (or >3 options), fall
371	  // back to a dropdown rather than wrap.
372	  const labelLen = (o) => String(typeof o === 'object' ? o.label : o).length;
373	  const maxLen = options.reduce((m, o) => Math.max(m, labelLen(o)), 0);
374	  const fitsAsSegments = maxLen <= ({ 2: 16, 3: 10 }[options.length] ?? 0);
375	  if (!fitsAsSegments) {
376	    // <select> emits strings — map back to the original option value so the
377	    // fallback stays type-preserving (numbers, booleans) like the segment path.
378	    const resolve = (s) => {
379	      const m = options.find((o) => String(typeof o === 'object' ? o.value : o) === s);
380	      return m === undefined ? s : typeof m === 'object' ? m.value : m;
381	    };
382	    return <TweakSelect label={label} value={value} options={options}
383	                        onChange={(s) => onChange(resolve(s))} />;
384	  }
385	  const opts = options.map((o) => (typeof o === 'object' ? o : { value: o, label: o }));
386	  const idx = Math.max(0, opts.findIndex((o) => o.value === value));
387	  const n = opts.length;
388	
389	  const segAt = (clientX) => {
390	    const r = trackRef.current.getBoundingClientRect();
391	    const inner = r.width - 4;
392	    const i = Math.floor(((clientX - r.left - 2) / inner) * n);
393	    return opts[Math.max(0, Math.min(n - 1, i))].value;
394	  };
395	
396	  const onPointerDown = (e) => {
397	    setDragging(true);
398	    const v0 = segAt(e.clientX);
399	    if (v0 !== valueRef.current) onChange(v0);
400	    const move = (ev) => {
401	      if (!trackRef.current) return;
402	      const v = segAt(ev.clientX);
403	      if (v !== valueRef.current) onChange(v);
404	    };
405	    const up = () => {
406	      setDragging(false);
407	      window.removeEventListener('pointermove', move);
408	      window.removeEventListener('pointerup', up);
409	    };
410	    window.addEventListener('pointermove', move);
411	    window.addEventListener('pointerup', up);
412	  };
413	
414	  return (
415	    <TweakRow label={label}>
416	      <div ref={trackRef} role="radiogroup" onPointerDown={onPointerDown}
417	           className={dragging ? 'twk-seg dragging' : 'twk-seg'}>
418	        <div className="twk-seg-thumb"
419	             style={{ left: `calc(2px + ${idx} * (100% - 4px) / ${n})`,
420	                      width: `calc((100% - 4px) / ${n})` }} />
421	        {opts.map((o) => (
422	          <button key={o.value} type="button" role="radio" aria-checked={o.value === value}>
423	            {o.label}
424	          </button>
425	        ))}
426	      </div>
427	    </TweakRow>
428	  );
429	}
430	
431	function TweakSelect({ label, value, options, onChange }) {
432	  return (
433	    <TweakRow label={label}>
434	      <select className="twk-field" value={value} onChange={(e) => onChange(e.target.value)}>
435	        {options.map((o) => {
436	          const v = typeof o === 'object' ? o.value : o;
437	          const l = typeof o === 'object' ? o.label : o;
438	          return <option key={v} value={v}>{l}</option>;
439	        })}
440	      </select>
441	    </TweakRow>
442	  );
443	}
444	
445	function TweakText({ label, value, placeholder, onChange }) {
446	  return (
447	    <TweakRow label={label}>
448	      <input className="twk-field" type="text" value={value} placeholder={placeholder}
449	             onChange={(e) => onChange(e.target.value)} />
450	    </TweakRow>
451	  );
452	}
453	
454	function TweakNumber({ label, value, min, max, step = 1, unit = '', onChange }) {
455	  const clamp = (n) => {
456	    if (min != null && n < min) return min;
457	    if (max != null && n > max) return max;
458	    return n;
459	  };
460	  const startRef = React.useRef({ x: 0, val: 0 });
461	  const onScrubStart = (e) => {
462	    e.preventDefault();
463	    startRef.current = { x: e.clientX, val: value };
464	    const decimals = (String(step).split('.')[1] || '').length;
465	    const move = (ev) => {
466	      const dx = ev.clientX - startRef.current.x;
467	      const raw = startRef.current.val + dx * step;
468	      const snapped = Math.round(raw / step) * step;
469	      onChange(clamp(Number(snapped.toFixed(decimals))));
470	    };
471	    const up = () => {
472	      window.removeEventListener('pointermove', move);
473	      window.removeEventListener('pointerup', up);
474	    };
475	    window.addEventListener('pointermove', move);
476	    window.addEventListener('pointerup', up);
477	  };
478	  return (
479	    <div className="twk-num">
480	      <span className="twk-num-lbl" onPointerDown={onScrubStart}>{label}</span>
481	      <input type="number" value={value} min={min} max={max} step={step}
482	             onChange={(e) => onChange(clamp(Number(e.target.value)))} />
483	      {unit && <span className="twk-num-unit">{unit}</span>}
484	    </div>
485	  );
486	}
487	
488	// Relative-luminance contrast pick — checkmarks drawn over a swatch need to
489	// read on both #111 and #fafafa without per-option configuration. Hex input
490	// only (#rgb / #rrggbb); named or rgb()/hsl() colors fall through to "light".
491	function __twkIsLight(hex) {
492	  const h = String(hex).replace('#', '');
493	  const x = h.length === 3 ? h.replace(/./g, (c) => c + c) : h.padEnd(6, '0');
494	  const n = parseInt(x.slice(0, 6), 16);
495	  if (Number.isNaN(n)) return true;
496	  const r = (n >> 16) & 255, g = (n >> 8) & 255, b = n & 255;
497	  return r * 299 + g * 587 + b * 114 > 148000;
498	}
499	
500	const __TwkCheck = ({ light }) => (
501	  <svg viewBox="0 0 14 14" aria-hidden="true">
502	    <path d="M3 7.2 5.8 10 11 4.2" fill="none" strokeWidth="2.2"
503	          strokeLinecap="round" strokeLinejoin="round"
504	          stroke={light ? 'rgba(0,0,0,.78)' : '#fff'} />
505	  </svg>
506	);
507	
508	// TweakColor — curated color/palette picker. Each option is either a single
509	// hex string or an array of 1-5 hex strings; the card adapts — a lone color
510	// renders solid, a palette renders colors[0] as the hero (left ~2/3) with the
511	// rest stacked in a sharp column on the right. onChange emits the
512	// option in the shape it was passed (string stays string, array stays array).
513	// Without options it falls back to the native color input for back-compat.
514	function TweakColor({ label, value, options, onChange }) {
515	  if (!options || !options.length) {
516	    return (
517	      <div className="twk-row twk-row-h">
518	        <div className="twk-lbl"><span>{label}</span></div>
519	        <input type="color" className="twk-swatch" value={value}
520	               onChange={(e) => onChange(e.target.value)} />
521	      </div>
522	    );
523	  }
524	  // Native <input type=color> emits lowercase hex per the HTML spec, so
525	  // compare case-insensitively. String() guards JSON.stringify(undefined),
526	  // which returns the primitive undefined (no .toLowerCase).
527	  const key = (o) => String(JSON.stringify(o)).toLowerCase();
528	  const cur = key(value);
529	  return (
530	    <TweakRow label={label}>
531	      <div className="twk-chips" role="radiogroup">
532	        {options.map((o, i) => {
533	          const colors = Array.isArray(o) ? o : [o];
534	          const [hero, ...rest] = colors;
535	          const sup = rest.slice(0, 4);
536	          const on = key(o) === cur;
537	          return (
538	            <button key={i} type="button" className="twk-chip" role="radio"
539	                    aria-checked={on} data-on={on ? '1' : '0'}
540	                    aria-label={colors.join(', ')} title={colors.join(' · ')}
541	                    style={{ background: hero }}
542	                    onClick={() => onChange(o)}>
543	              {sup.length > 0 && (
544	                <span>
545	                  {sup.map((c, j) => <i key={j} style={{ background: c }} />)}
546	                </span>
547	              )}
548	              {on && <__TwkCheck light={__twkIsLight(hero)} />}
549	            </button>
550	          );
551	        })}
552	      </div>
553	    </TweakRow>
554	  );
555	}
556	
557	function TweakButton({ label, onClick, secondary = false }) {
558	  return (
559	    <button type="button" className={secondary ? 'twk-btn secondary' : 'twk-btn'}
560	            onClick={onClick}>{label}</button>
561	  );
562	}
563	
564	Object.assign(window, {
565	  useTweaks, TweaksPanel, TweakSection, TweakRow,
566	  TweakSlider, TweakToggle, TweakRadio, TweakSelect,
567	  TweakText, TweakNumber, TweakColor, TweakButton,
568	});
